INSERT INTO beans (id,name,origin,region,variety,altitude,process,terroir,status,is_new,price,description_ja,description_en,taste_ja,taste_en,detail_ja,detail_en) VALUES
(1,'Sample Bean A','[[パナマ|country:panama]]','[[Hacienda La Esmeralda|farm:esmeralda]]','[[Geisha|term:geisha]]','1,600-2,200m','[[Washed|process:washed]]','','リリース中',true,1200,'サンプル豆の概要文です。','','サンプルのテイストノートです。','Sample tasting note.','',''),
(2,'Ethiopia Tamiru Tadesse Chilaka','[[エチオピア|country:ethiopia]]','Sidama, Bensa, Chilaka village / [[ALO Coffee|farm:alo-coffee]]','74158','2,360-2,460m','[[Classic Washed|process:washed]]','','リリース中',true,0,'ALO COFFEEの単一農園に当たるチャラカ。2021年のCOEでは1位と5位の同時入賞の経験もあるタミル・タデッセ氏が手掛けています。','Chilaka is a single-farm lot from ALO Coffee, produced by Tamiru Tadesse.','アロマでは微かにフローラル。フレーバーではレモン、黄桃、ブラウンシュガー、バニラを感じていただけます。','The flavor you''ll find is lemon, yellow peach, brown sugar, vanilla.','発酵層での発酵時間は48時間。その後天日乾燥。',''),
(3,'Esmeralda Mario','[[パナマ|country:panama]]','Boquete, Chiriqui / [[Hacienda La Esmeralda|farm:esmeralda]] / Jaramillo, Mario区画 (4GW)','[[Geisha|term:geisha]]','1,600-1,800m','[[Washed|process:washed]]','エスメラルダスペシャル（Red Box）','リリース中',true,8500,'Esmeraldaは、Geisha種を世界に広めた農園として知られています。Marioロットは[[Hacienda La Esmeralda|farm:esmeralda]]のJaramilloエリア、Mario区画で生産されたGeisha種です。','Esmeralda is the farm that made Geisha famous around the world. This lot comes from the Mario plot.','アロマではジャスミン、オレンジブロッサム、ガーデニア。フレーバーでは、ガーデニア、ピーチ、グレープフルーツ、はちみつを感じていただけます。','The flavor brings gardenia, orange blossom, peach, grapefruit, and honey.','過去のBest of Panamaで史上最高スコアを獲得した伝説的ロットも同じJaramillo・Mario区画から生まれています。カッピングスコア91点以上の「エスメラルダスペシャル」クラスのロットです。',''),
(4,'Esmeralda Reina','[[パナマ|country:panama]]','Boquete, Chiriqui / [[Hacienda La Esmeralda|farm:esmeralda]] / Jaramillo, Reina区画 (3NB)','[[Geisha|term:geisha]]','1,600-1,800m','[[Natural|process:natural]]','エスメラルダスペシャル（Red Box）','リリース中',true,8000,'Reinaロットはパナマゲイシャはじまりの地のJaramilloエリアの中でも、繊細さやジャスミンのようなフローラルさが特徴的なReina区画で収穫されたGeisha種です。','Esmeralda Reina comes from the Reina plot. It is a natural process coffee, dried slowly for 29 days.','アロマではジャスミンやローズ。フレーバーでは、ジャスミン、オレンジ、青りんご、ベリー、プラム、はちみつ。','The flavor includes jasmine, orange, green apple, berry, plum, and honey.','アフリカンベッドで29日間かけてゆっくり乾燥。カッピングスコア91点以上の「エスメラルダスペシャル」クラスのロットです。',''),
(5,'Flying Pumas White-Faced Capuchin Monkey 2.3','[[パナマ|country:panama]]','Volcán, Chiriqui / [[Flying Pumas|farm:flying-pumas]] / White-Faced Capuchin Monkey区画','[[Geisha|term:geisha]]','1,650-2,200m','[[Anaerobic Natural|process:anaerobic-natural]]','Iconic Series','リリース中',true,0,'Flying Pumasは2019年設立。競技会レベルのクオリティと環境保全の両立を実現している農園です。','Flying Pumas was established in 2019, known for competition-level quality and sustainability.','アロマではヴィオラ。フレーバーはヴィオラ、ブラッドオレンジ、プラム、サングリア、はちみつ。','The flavor is viola, blood orange, plum, sangria, and honey.','190時間嫌気性発酵後、40日間乾燥。',''),
(6,'Costa Rica San Isidro Labrador Geisha Honey','[[コスタリカ|country:costa-rica]]','Tarrazu / [[San Isidro Labrador|farm:san-isidro-labrador]]','[[Geisha|term:geisha]]','1,900-1,950m','[[Experimental Honey|process:experimental-honey]]','','リリース中',true,0,'タラスの高地にある家族経営農園。COE初出場2位、その後6年連続入賞、2023年優勝を果たした新鋭農園です。','A family-run farm in Tarrazú, Costa Rica, placed 2nd in their first COE and won in 2023.','アロマではハニーサックル。フレーバーではハニーサックル、日向夏、ストーンフルーツ、ハチミツ。','The flavor you''ll find is honeysuckle, Hyuganatsu, stone fruit, and honey.','COE：2020年初出場2位、2023年優勝。',''),
(7,'Gesha Village SURMA','[[エチオピア|country:ethiopia]]','Bench Maji / [[Gesha Village|farm:gesha-village]] / Surma区画','[[Geisha 1931|term:geisha-1931]]','1,900-2,063m','[[Natural|process:natural]]','Santuario Project','リリース中',true,0,'ゲシャビレッジはエチオピア内でも最高品質のゲイシャ種を栽培。SURMA区画は華やかなフローラルと柔らかく繊細なフレーバーが特徴です。','Gesha Village grows high-quality Geisha coffee. The Surma block is known for floral and delicate flavors.','アロマではジャスミン。フレーバーは白い花、ジャスミン、レモン、紅茶、ストーンフルーツ、ハチミツ。','The flavor you''ll find is white flowers, jasmine, lemon, black tea, stone fruit, and honey.','Santuario Projectとの共同ロット。',''),
(8,'illumination','[[パナマ|country:panama]]','Boquete, Chiriqui / [[Don Eduardo Estate|farm:don-eduardo]]','[[Geisha|term:geisha]]','1,850m','[[Carbonic Maceration Washed|process:cm-washed]]','','リリース中',true,0,'Don Eduardo EstateのHarold SabinはかつてSavage Coffeeを10年以上牽引した人物です。','"Illumination" is produced by Don Eduardo Estate, owned by Harold Sabin.','アロマではジャスミンや微かにカモミール。フレーバーでは、ジャスミン、カモミール、チェリー、リンゴ、蜂蜜、バニラ。','The flavor you''ll find is jasmine, chamomile, cherry, apple, honey, and vanilla.','2017年にグリーンチップゲイシャの木を貰い受けた。',''),
(9,'Los Nogales Pink Bourbon PW','[[コロンビア|country:colombia]]','Bruselas, Huila / [[Los Nogales|farm:los-nogales]]','[[Pink Bourbon|term:pink-bourbon]]','1,800m','[[Washed Fermented|process:washed-fermented]]','','リリース中',true,0,'Los Nogalesは父Rigoberto氏が2005年COEの初代優勝者。80℃の温水処理・急冷・モストを用いた120時間発酵で仕上げています。','Los Nogales Farm''s Pink Bourbon, processed with 120-hour fermentation.','アロマではトロピカルフルーツ。フレーバーでは、トロピカルフルーツ、完熟オレンジ、ネクタロープ、レッドカラント、はちみつ、チョコレート。','The flavor you''ll find is tropical fruits, ripe orange, nectarine, red currant, honey, and chocolate.','約15日間天日乾燥。',''),
(10,'Los Nogales Caturra PW','[[コロンビア|country:colombia]]','Bruselas, Huila / [[Los Nogales|farm:los-nogales]]','[[Caturra|term:caturra]]','1,800m','[[Washed Fermented|process:washed-fermented]]','','リリース中',true,0,'Los Nogalesのカトゥーラ。同農園のWashed Fermentedプロセスで仕上げています。','The flavor you''ll find is tropical fruits, cherry, cantaloupe, orange, and honey.','アロマではトロピカルフルーツやチェリー。フレーバーでは、トロピカル、チェリー、カンタロープ、オレンジ、はちみつ。','The flavors you''ll find are tropical fruits...','約15日間天日乾燥。',''),
(18,'Kii AB Washed','[[ケニア|country:kenya]]','Kirinyaga County / [[Kii Factory|farm:kii-factory]]','[[SL28|term:sl28]] / [[SL34|term:sl34]] / [[Batian|term:batian]] / [[Ruiru 11|term:ruiru-11]]','1,600-1,800m','[[Fully Washed|process:fully-washed]]','Rungeto FCS / AB Grade','リリース中',true,0,'キイ ファクトリーは1965年にケニア山の麓に設立。ルンゲト組合が1995年から運営しています。','Kii Factory was established in 1965 at the foot of Mount Kenya.','アロマではオレンジやブラックカラント。フレーバーではオレンジ、ブラックカラント、クローブ。','Orange, Black Currant, Floral, Clove, Sweet, Thick, Juicy.','クロップ：24/25 / 規格：AB',''),
(19,'Los Nogales Orange Bourbon Lavender Fusion','[[コロンビア|country:colombia]]','Bruselas, Huila / [[Los Nogales|farm:los-nogales]] / Lot Yarumo','[[Orange Bourbon|term:orange-bourbon]]','1,900m','[[Lavender Fusion|process:lavender-fusion]]','','リリース中',true,0,'Los Nogalesの「テロワール」「ジェネティック」「サイエンス」を体現するOrange Bourbon。約3週間ラベンダーの花とともに乾燥させます。','Los Nogales Orange Bourbon, dried for 3 weeks alongside lavender flowers.','ラベンダーのフローラルさとイエローフルーツやオレンジ、パパイヤのようなジューシーなフレーバー。','Lavender floral notes combined with juicy flavors of yellow fruit, orange, and papaya.','24時間発酵後、約3週間ラベンダーと共に乾燥。',''),
(20,'La Terraza Chiroso Washed','[[コロンビア|country:colombia]]','La Argentina, Huila / [[La Terraza|farm:la-terraza]]','[[Chiroso|term:chiroso]]','1,800m','[[Washed|process:washed]]','','リリース中',true,0,'ウイラ県アルヘンティーナ地区のコーヒー。生産者はヘイゼル・フリアナ・ゲバラ氏。Terra Coffeeを通じて届けられています。','This coffee comes from the Argentina region of Huila, produced by Hazel Juliana Guevara.','','','エクスポーター：Terra Coffee / 品番：TR28',''),
(11,'Alo Village Yabai','[[エチオピア|country:ethiopia]]','Sidama, Bensa, Alo / [[ALO Coffee|farm:alo-coffee]]','74158','2,450m+','[[Extended Fermentation Natural|process:extended-fermentation-natural]]','Sky Project','終売',false,0,'2016年WBrCチャンピオン粕谷哲さん、Alo Coffee、Tri-up社の三者コラボロットです。','A special collaboration by Tetsu Kasuya, Alo Coffee, and Tri-Up.','アロマでは鮮やかなブドウとフローラル。フレーバーではフローラル、赤ぶどう、巨峰、蜂蜜。','The flavor you''ll find floral, red grape, kyoho grape, and honey.','3年目：Extended Fermentation Natural。',''),
(12,'Nigussei Gemeda Mude','[[エチオピア|country:ethiopia]]','Sidama, Bura Woreda, Morke Kebele / KARAMO COFFEE EXPORT','74158','2,400m','[[Natural|process:natural]]','','終売',false,0,'エチオピアCOE初代優勝者ニグセ氏のカラモ・モルケ村ロットです。','This coffee is made by Niguse, the first Cup of Excellence winner from Ethiopia.','アロマではマスカット。フレーバーでは、マスカット、白桃、アプリコット、ヨーグルト、ハチミツ。','The flavor you''ll find is muscat, white peach, apricot, yogurt, honey.','2017年にKARAMO COFFEE EXPORTを設立。',''),
(13,'Bona JH Washed','[[エチオピア|country:ethiopia]]','Sidama, Bensa, Bona','74112, 74158','2,400m','[[JH Washed|process:jh-washed]]','','終売',false,0,'Jake HuとTri-Up社が5年以上かけて開発したJH Washedプロセスを使用しています。','This coffee is made by Jake Hu and Taiwan''s Tri-Up.','アロマはジャスミンやローズウォーター。フレーバーではジャスミン、ローズウォーター、グレープフルーツ、黄桃、ブラウンシュガー。','The flavor you''ll find is jasmine, rose water, grape fruit, yellow peach and brown sugar.','JH株という微生物を個別培養。',''),
(14,'El Pinal','[[グアテマラ|country:guatemala]]','Jalapa / [[El Pinal|farm:el-pinal]]','[[Geisha|term:geisha]]','1,450-1,550m','[[Fully Washed|process:fully-washed]]','','終売',false,0,'エル・ピナル農園はグアテマラのハラパ県にある20年の歴史を持つ農園です。','El Pinal Farm is in Jalapa, Guatemala, with a 20-year history.','アロマではジャスミンや微かにカモミール。緑茶や白いグレープフルーツ、ストーンフルーツのフレーバー。','The flavor you''ll find is white grape fruit, stone fruit, green tea, almond.','ACOGUAに加入。',''),
(15,'ALO Village White Honey','[[エチオピア|country:ethiopia]]','Sidama, Bensa, Alo / [[ALO Coffee|farm:alo-coffee]]','74158','2,400m+','[[White Honey|process:white-honey]]','','終売',false,0,'ALO COFFEEは高い標高にウォッシングステーションを持ち、エチオピアでは珍しいハニープロセスをリリースしています。','ALO COFFEE''s washing station is at a very high altitude, releasing honey process.','アロマではジャスミン。フレーバーはジャスミン、オレンジ、ネクタリン、オレンジブロッサムとブラウンスパイス。','The flavor you''ll find jasmine, orange, nectarine, orange blossom, brown spice.','高性能パルピング機を使用。',''),
(16,'Simbi CWS','[[ルワンダ|country:rwanda]]','Huye District, South Province / [[Simbi CWS|farm:simbi-cws]]','[[Bourbon|term:bourbon]]','1,800m','[[Natural|process:natural]]','','終売',false,0,'シンビウォッシングステーションはクリーンで甘さのある味わいが特徴です。','Simbi Washing Station is known for its clean and sweet cup.','アロマではクランベリーやチェリー。フレーバーでは、クランベリー、チェリー、ハチミツ、カシス。','The flavor you''ll find is cranberry, cherry, honey, and cassis.','2013年設立。',''),
(17,'Honduras Caballero','[[ホンジュラス|country:honduras]]','Pedemal, San Jose, La Paz / [[La Tina|farm:la-tina]]','[[Catuai|term:catuai]]','1,500m','[[Fully Washed|process:fully-washed]]','','終売',false,0,'マリサベル・カバレロとモイセス・ヘレラが手がけるラ・ティナ農園のコーヒーです。','This coffee comes from Finca La Tina, produced by Marysabel Caballero and Moises Herrera.','アロマでは柔らかいオレンジの香り。フレーバーではオレンジ、赤リンゴ、ヘーゼルナッツ、ダージリンティー、ブラウンシュガー。','The flavor you''ll find is orange, red apple, hazelnut, Darjeeling tea, and brown sugar.','2016年COEでEl Puenteが1位を獲得。','')
INSERT INTO countries (slug,name,flag,region,altitude,climate,overview) VALUES
('panama','パナマ','🇵🇦','チリキ県 / ボケテ / ボルカン','1,400-2,200m','バル火山の西・東斜面で気候が異なる。','Geisha種の聖地として世界的に知られる。'),
('ethiopia','エチオピア','🇪🇹','シダマ / イルガチェフェ / ベンサ','1,800-2,500m','高標高による低温と明確な乾季。','コーヒー発祥の地。'),
('costa-rica','コスタリカ','🇨🇷','タラス / セントラルバレー','1,200-2,000m','雨季と乾季が明確。','COE優勝農園も多く、クリーンで透明感のある味わいが特徴。'),
('colombia','コロンビア','🇨🇴','ウイラ / ナリーニョ / カウカ','1,500-2,200m','二期作が可能な安定した気候。','世界有数のスペシャルティコーヒー産地。'),
('guatemala','グアテマラ','🇬🇹','ハラパ / アンティグア','1,300-2,000m','火山性土壌と昼夜の寒暖差が特徴。','火山起源のミネラルが多い土壌によるカップの複雑さが特徴。'),
('rwanda','ルワンダ','🇷🇼','南部州 / 北部州','1,500-2,000m','丘陵地が多く高標高。','CWSを中心とした生産体制が特徴。'),
('honduras','ホンジュラス','🇭🇳','ラ・パス / コパン','1,000-1,800m','ラ・パス県は高標高×冷涼。','中米最大のコーヒー生産国のひとつ。'),
('kenya','ケニア','🇰🇪','キリニャガ / ニエリ','1,400-2,200m','ケニア山周辺の高標高地帯。','SL28・SL34などケニア固有品種が世界的に高く評価されている。')
INSERT INTO processes (slug,name,category,body) VALUES
('washed','Washed','ウォッシュド系','果肉除去→発酵→水洗いで乾燥。クリーンで透明感のある味わい。'),
('natural','Natural','ナチュラル系','チェリーのまま乾燥。果実由来の甘みや複雑なフレーバー。'),
('anaerobic-natural','Anaerobic Natural','アナエロビック系','密封容器内で嫌気性発酵させた後、乾燥。フローラルや果実感が引き出される。'),
('experimental-honey','Experimental Honey','ハニー系','ミューシレージを意図的に残して乾燥させる実験的バリエーション。'),
('cm-washed','Carbonic Maceration Washed','カーボニックマセレーション系','CO₂充填環境で発酵後、ウォッシュドで仕上げる。Savage Coffeeが初導入。'),
('washed-fermented','Washed Fermented','ウォッシュド系','温水処理と冷水急冷を経て、モストを加えた発酵を行いウォッシュドで仕上げる。'),
('extended-fermentation-natural','Extended Fermentation Natural','ナチュラル系','長時間発酵させてから乾燥するナチュラルプロセスの拡張版。'),
('jh-washed','JH Washed','ウォッシュド系','Tri-Up社とJake Huが開発したプロセス。微生物（JH株）を用いてウォッシュドで仕上げる。'),
('white-honey','White Honey','ハニー系','ミューシレージ除去率が最も高いハニープロセス。'),
('fully-washed','Fully Washed','ウォッシュド系','果肉とミューシレージを完全に洗い流して乾燥させるプロセス。'),
('lavender-fusion','Lavender Fusion','ナチュラル系','発酵後、ラベンダーの花と共にゆっくり乾燥させるプロセス。Los Nogalesが開発。')
INSERT INTO terms (slug,name,category,body) VALUES
('geisha','Geisha','品種','エチオピア・ゲシャ村原産。ジャスミン・白桃などのフローラルさと明るい酸が特徴。'),
('geisha-1931','Geisha 1931','品種','Gesha Villageが保有するGeisha種の原種系統。'),
('pink-bourbon','Pink Bourbon','品種','繊細なフローラルの香りと透明感のある味わいを持つ品種。'),
('caturra','Caturra','品種','コロンビアのベーシックな品種。クリーンさやナッツ系のフレーバー。'),
('catuai','Catuai','品種','ムンドノーボとカトゥーラの交配種。中米で広く栽培される。'),
('bourbon','Bourbon','品種','アラビカ種の原種に近い品種。甘さとコクのあるフレーバー。'),
('sl28','SL28','品種','ケニアを代表するフラッグシップ品種。ブラックカラント・プラムのような明るい酸。'),
('sl34','SL34','品種','SL28に似た風味で、より多雨条件に適応している。'),
('batian','Batian','品種','ケニア・コーヒー研究所が開発した病害虫耐性品種。'),
('ruiru-11','Ruiru 11','品種','病害虫耐性と高収量を重視したハイブリッド品種。'),
('orange-bourbon','Orange Bourbon','品種','チェリーが熟すとオレンジ色になるブルボン種の変異体。'),
('chiroso','Chiroso','品種','コロンビアで栽培される細長い豆が特徴の品種。Geishaに似たフローラルさ。'),
('best-of-panama','Best of Panama (BOP)','大会・認証','パナマの品評会・国際オークション。Hacienda La Esmeraldaは2004年に初優勝。')
INSERT INTO farms (slug,name,country_slug,country_name,location,owner,altitude,overview,areas,ranks,awards) VALUES
('esmeralda','Hacienda La Esmeralda','panama','パナマ','Boquete, Chiriqui','Rachel Peterson','1,600-2,200m','Geisha種を世界に広めた農園として知られ、今もコーヒー界の最前線を走り続ける名門農園。2004年のBest of Panama（BOP）で初優勝し、当時は無名に近かったGeisha種が1ポンド21ドルの落札価格を記録（同区画Jaramillo Especial）。2007年には1ポンド130ドルまで価格が上昇した。2024年のオークションでは最高落札価格$10,013/kgを記録し、2025年のBOPでは史上初の3部門（Geisha Washed・Geisha Natural・Varietal）同時優勝を達成。Geisha Washed部門98.00点、Geisha Natural部門97.00点という最高得点を更新した。2025年のオークション結果はWashed $30,204/kg（前年比約3倍）、Natural $23,608/kg、Varietal $8,040/kgという驚異的な価格となった。Washed・NaturalはCañas Verdesの豆、VarietalはEl Veloの豆。生産者のRachel PetersonはForbes Centroaméricaで「中米に影響を与える女性リーダー」として紹介されるなど、コーヒー業界を超えた評価を受けている。','[{"name":"Jaramillo","description":"2004年のオークションで高評価を受けたエリアで、パナマGeishaはじまりの地。フローラルが特徴で、ジャスミン・ベルガモット・白桃のような透明感のあるカップ。MarioやReinaなどの区画がこのエリアに属する。公式: https://haciendaesmeralda.com/jaramillo-farm/"},{"name":"Cañas Verdes","description":"Jaramilloに比べ柔らかさのあるカップで、甘みや丸みのある質感、シトラスやはちみつ、黄桃のような傾向。Nido区画は最高標高で、2025年三冠達成ロット（Washed/Natural）もここから生まれた。公式: https://haciendaesmeralda.com/canas-verdes-farm/"},{"name":"El Velo","description":"Esmeralda内で最も高標高のエリア。強さのある伸びやかな酸と華やかさ、白い花・白葡萄・ライムのような透明感の強いカップ。実験的エリアでGeishaに加えVarietal系のCatuaiなども栽培。公式: https://haciendaesmeralda.com/el-velo-farm/"}]','[{"name":"プライベートオークションロット（Black Box）","description":"最高峰のオークションロット。年1回のオンラインオークション「エスメラルダ・スペシャル・オークション」でのみ購入可能な、数量限定の超希少マイクロロット。Best of Panamaへの出品候補レベル。"},{"name":"エスメラルダスペシャル（Red Box）","description":"標高1950m以上、カッピングスコア91点以上のGeisha種。栽培エリアが明記され、オークション以外で購入できる中では最高クラス。"},{"name":"プライベートコレクション（Green Box）","description":"標高1600〜1800mの高地エリアで栽培され、カッピングスコア87〜90点を保証。区画までは明記されない。"},{"name":"ロット表記について","description":"ロット名は「数字＋アルファベット」で構成される。数字は同区画内での収穫順（大きいほど収穫が遅く、標高が高い傾向）。アルファベットは精製方法を表す：N=Natural／W=Washed（屋外タンクで常温発酵）／A=Anaerobic／F=低温室で発酵／C=クライメートコントロール（温湿度管理された部屋での乾燥、高品質・高価格）／P=パティオ乾燥／B=アフリカンベッド乾燥。例：「Mario 4GW」「Reina 3NB」（Gはゲイシャを示す）。9番以降は均一性を保てないためブレンドされプライベートロットとして扱われる。"}]','2004年　Best of Panama 初優勝（Jaramillo Especial、1ポンド21ドルで当時最高落札価格）
